#include <stdio.h>

void writeErrorMessageToLogFile(const char* logFileName, const char *errorMsg){ 
    FILE *logfile = fopen (logFileName , "a"); // append mode is used here to keep the logs even after program termination or restarted  
     if (!logfile) { 
        printf("Could not open file %s for writing\n", logFileName); 
         return;   
      } else{         
       fprintf(logfile, "%s" , errorMsg ); // user input is directly written into the logs without any formatting vulnerabilities.  
     }          
        fclose (logfile) ;            
}